function App() {
  const [meals, setMeals] = React.useState([
    { id: 1, emoji: '🥣', name: 'Oatmeal with berries', cal: 320, p: 12, c: 52, f: 8, time: '8:00 AM' },
    { id: 2, emoji: '🥗', name: 'Grilled chicken salad', cal: 450, p: 42, c: 18, f: 16, time: '12:30 PM' },
    { id: 3, emoji: '🍦', name: 'Greek yogurt', cal: 150, p: 15, c: 12, f: 4, time: '3:00 PM' },
  ]);
  const [showAdd, setShowAdd] = React.useState(false);
  const [newMeal, setNewMeal] = React.useState('');

  const totals = meals.reduce((acc, m) => ({ cal: acc.cal + m.cal, p: acc.p + m.p, c: acc.c + m.c, f: acc.f + m.f }), { cal: 0, p: 0, c: 0, f: 0 });
  const goals = { cal: 2000, p: 150, c: 200, f: 65 };

  const handleAdd = () => {
    if (!newMeal.trim()) return;
    setMeals([...meals, { id: Date.now(), emoji: '🍽️', name: newMeal, cal: 200, p: 10, c: 25, f: 8, time: 'Now' }]);
    setNewMeal('');
    setShowAdd(false);
  };

  const macroBarClass = { Protein: 'bg-blue-500', Carbs: 'bg-orange-500', Fat: 'bg-yellow-400' };

  const macros = [
    { label: 'Protein', value: totals.p, goal: goals.p },
    { label: 'Carbs', value: totals.c, goal: goals.c },
    { label: 'Fat', value: totals.f, goal: goals.f },
  ];

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto font-sans">
      {/* Header */}
      <div className="bg-white px-5 pt-4 pb-3 border-b border-slate-100">
        <div className="text-[11px] text-slate-400 mb-0.5">Monday, March 24</div>
        <div className="text-[22px] font-extrabold text-slate-900">Meal Log</div>
      </div>

      {/* Calorie Summary Card */}
      <div className="mx-4 mt-4 bg-white rounded-[20px] p-5 shadow-sm">
        <div className="flex justify-between items-center mb-2">
          <div>
            <span className="text-[28px] font-extrabold text-slate-900">{totals.cal}</span>
            <span className="text-[13px] text-slate-400 ml-1">/ {goals.cal} kcal</span>
          </div>
          <div className="text-[13px] text-slate-500 bg-slate-100 rounded-full px-3 py-1">
            {goals.cal - totals.cal} left
          </div>
        </div>
        <div className="h-2 bg-slate-100 rounded-full overflow-hidden mb-4">
          <div className="h-full bg-gradient-to-r from-blue-500 to-indigo-500 rounded-full transition-[width] duration-300" style={{ width: `${Math.min((totals.cal / goals.cal) * 100, 100)}%` }} />
        </div>
        <div className="grid grid-cols-3 gap-3">
          {macros.map(m => (
            <div key={m.label} className="text-center">
              <div className="text-[15px] font-bold text-slate-900">{m.value}g</div>
              <div className="text-[11px] text-slate-400 mb-1">{m.label}</div>
              <div className="h-1 bg-slate-100 rounded-full">
                <div className={`h-full rounded-full ${macroBarClass[m.label]}`} style={{ width: `${Math.min((m.value / m.goal) * 100, 100)}%` }} />
              </div>
            </div>
          ))}
        </div>
      </div>

      {/* Meal List */}
      <div className="px-4 pt-4 pb-[100px]">
        <div className="text-[13px] font-semibold text-slate-500 mb-2.5 pl-1">TODAY'S MEALS</div>
        {meals.map(meal => (
          <div key={meal.id} className="bg-white rounded-2xl px-4 py-3.5 mb-2.5 flex items-center gap-3.5 shadow-sm">
            <div className="w-11 h-11 bg-sky-50 rounded-[14px] flex items-center justify-center text-[22px] shrink-0">{meal.emoji}</div>
            <div className="flex-1 min-w-0">
              <div className="text-[14px] font-semibold text-slate-900 whitespace-nowrap overflow-hidden text-ellipsis">{meal.name}</div>
              <div className="text-[12px] text-slate-400 mt-0.5">{meal.time} · P {meal.p}g · C {meal.c}g · F {meal.f}g</div>
            </div>
            <div className="text-[15px] font-bold text-gray-700 shrink-0">{meal.cal}</div>
          </div>
        ))}
      </div>

      {/* Add Modal */}
      {showAdd && (
        <div className="fixed inset-0 bg-black/30 flex items-end z-50" onClick={() => setShowAdd(false)}>
          <div className="bg-white rounded-t-3xl p-6 w-full" onClick={e => e.stopPropagation()}>
            <div className="text-[18px] font-bold mb-4">Add Meal</div>
            <input value={newMeal} onChange={e => setNewMeal(e.target.value)} placeholder="What did you eat?" autoFocus
              className="w-full border-[1.5px] border-slate-200 rounded-xl px-3.5 py-3 text-[15px] outline-none box-border" />
            <button onClick={handleAdd} className="w-full mt-3 bg-blue-500 text-white border-none rounded-[14px] py-3.5 text-[15px] font-semibold cursor-pointer">
              Log Meal
            </button>
          </div>
        </div>
      )}

      {/* FAB */}
      <button onClick={() => setShowAdd(true)} className="fixed bottom-7 right-7 w-14 h-14 bg-gradient-to-br from-blue-500 to-indigo-500 border-none rounded-full text-white text-[28px] cursor-pointer shadow-[0_4px_14px_rgba(59,130,246,0.4)] flex items-center justify-center">+</button>
    </div>
  );
}

function App() {
  const [period, setPeriod] = React.useState('week');
  const [activeGoal, setActiveGoal] = React.useState(null);

  const weekData = [
    { day: 'Mon', cal: 1820, goal: 2000 },
    { day: 'Tue', cal: 2100, goal: 2000 },
    { day: 'Wed', cal: 1650, goal: 2000 },
    { day: 'Thu', cal: 1920, goal: 2000 },
    { day: 'Fri', cal: 2200, goal: 2000 },
    { day: 'Sat', cal: 1500, goal: 2000 },
    { day: 'Sun', cal: 920, goal: 2000 },
  ];
  const maxCal = Math.max(...weekData.map(d => d.cal));

  const goalBarClass = { 1: 'bg-blue-500', 2: 'bg-emerald-500', 3: 'bg-orange-500' };

  const goals = [
    { id: 1, label: 'Lose 5kg', progress: 62, detail: '3.1 kg lost' },
    { id: 2, label: 'Daily Protein', progress: 80, detail: '120g / 150g' },
    { id: 3, label: 'Calorie Deficit', progress: 45, detail: '5 of 7 days' },
  ];

  const stats = [
    { label: 'Avg Calories', value: '1,730', sub: 'kcal/day', emoji: '🔥' },
    { label: 'Best Day', value: 'Tuesday', sub: '2,100 kcal', emoji: '⭐' },
    { label: 'Logged Days', value: '6/7', sub: 'this week', emoji: '📅' },
  ];

  return (
    <div className="min-h-screen bg-slate-50 font-sans max-w-[390px] mx-auto pb-8 font-sans">
      <div className="bg-white px-5 pt-4 pb-3 border-b border-slate-100">
        <div className="text-[22px] font-bold text-slate-900">Progress</div>
        <div className="flex gap-2 mt-3">
          {['week', 'month', '3m'].map(p => (
            <button key={p} onClick={() => setPeriod(p)} className={`px-4 py-1.5 rounded-full border-none cursor-pointer text-[13px] font-semibold ${period === p ? 'bg-blue-500 text-white' : 'bg-slate-100 text-slate-500'}`}>
              {p === 'week' ? 'Week' : p === 'month' ? 'Month' : '3 Months'}
            </button>
          ))}
        </div>
      </div>

      {/* Bar Chart */}
      <div className="mx-4 mt-4 bg-white rounded-[20px] p-5 shadow-sm">
        <div className="text-[15px] font-bold text-slate-900 mb-4">Calorie Intake</div>
        <div className="flex items-end gap-2 h-[100px]">
          {weekData.map(d => (
            <div key={d.day} className="flex-1 flex flex-col items-center gap-1">
              <div className={`w-full rounded-md flex items-end h-20 ${d.cal >= d.goal ? 'bg-amber-50' : 'bg-blue-50'}`}>
                <div className={`w-full rounded-md transition-[height] duration-300 ${d.cal >= d.goal ? 'bg-amber-400' : 'bg-blue-500'}`} style={{ height: `${(d.cal / maxCal) * 80}px` }} />
              </div>
              <div className="text-[11px] text-slate-400">{d.day}</div>
            </div>
          ))}
        </div>
        <div className="flex items-center gap-4 mt-3 text-[12px] text-slate-500">
          <span>🔵 Under goal</span>
          <span>🟡 Over goal</span>
          <span className="ml-auto">Goal: 2,000 kcal</span>
        </div>
      </div>

      {/* Stats Row */}
      <div className="grid grid-cols-3 gap-2.5 mx-4 mt-3">
        {stats.map(s => (
          <div key={s.label} className="bg-white rounded-2xl px-2.5 py-3.5 text-center shadow-sm">
            <div className="text-[22px]">{s.emoji}</div>
            <div className="text-[14px] font-bold text-slate-900 mt-1">{s.value}</div>
            <div className="text-[10px] text-slate-400">{s.label}</div>
            <div className="text-[10px] text-slate-500">{s.sub}</div>
          </div>
        ))}
      </div>

      {/* Goals */}
      <div className="mx-4 mt-3 bg-white rounded-[20px] p-5 shadow-sm">
        <div className="flex justify-between items-center mb-4">
          <div className="text-[15px] font-bold text-slate-900">Goals</div>
          <button className="text-[13px] text-blue-500 bg-transparent border-none cursor-pointer font-semibold">+ Add Goal</button>
        </div>
        {goals.map(g => (
          <div key={g.id} onClick={() => setActiveGoal(activeGoal === g.id ? null : g.id)} className="mb-4 cursor-pointer">
            <div className="flex justify-between mb-1.5">
              <span className="text-[14px] font-semibold text-slate-900">{g.label}</span>
              <span className="text-[13px] text-slate-500">{g.progress}% · {g.detail}</span>
            </div>
            <div className="h-2 bg-slate-100 rounded-full">
              <div className={`h-full rounded-full transition-[width] duration-300 ${goalBarClass[g.id]}`} style={{ width: `${g.progress}%` }} />
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
